import React from 'react';
import { Link, NavLink } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';

const publicLinks = [
  { to: '/', label: 'Home' },
  { to: '/about', label: 'About' },
  { to: '/how-it-works', label: 'How It Works' },
  { to: '/eligibility', label: 'Eligibility' },
  { to: '/contact', label: 'Contact' },
];

function AdminLayout({ children }) {
  const { auth, logout } = useAuth();
  const isAdminLoggedIn = Boolean(auth?.token && auth?.user?.role === 'ADMIN');

  return (
    <div className="admin-site-shell">
      <header className="admin-public-header">
        <div className="admin-public-header-inner">
          <Link to="/" className="brand-link">
            <span className="brand-mark">CareFlow</span>
            <span className="brand-subtitle">Blood and Organ Donation Network</span>
          </Link>

          <nav className="public-nav" aria-label="Public navigation">
            {publicLinks.map((item) => (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === '/'}
                className={({ isActive }) => (isActive ? 'public-nav-link active' : 'public-nav-link')}
              >
                {item.label}
              </NavLink>
            ))}
          </nav>

          {isAdminLoggedIn && (
            <div className="admin-header-avatar" title={auth?.user?.username || 'admin'}>
              <span className="admin-header-avatar-fallback">A</span>
            </div>
          )}
        </div>
      </header>

      <div className="admin-site-grid">
        <aside className="admin-sidebar panel">
          <div>
            <p className="eyebrow">Operations</p>
            <h1>CareFlow Admin Console</h1>
            <p className="subtitle">Unified workspace for governance, requests, and platform control.</p>
          </div>

          <nav className="admin-sidebar-nav">
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/admin/overview">Overview</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/admin/requests">Requests Inbox</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/admin/users">User Governance</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/admin/operations">Operations Center</NavLink>
          </nav>

          <div className="admin-site-actions">
            <button className="danger" onClick={logout}>Logout</button>
          </div>
        </aside>

        <main className="admin-site-main">
          {children}
        </main>
      </div>
    </div>
  );
}

export default AdminLayout;
